<?phpnamespace App\Controller\Admin;use App\Entity\BienClient;use App\Entity\Expertise;use App\Entity\MemoBien;use App\Entity\OtherInfoBien;use App\Entity\RemarqueBien;use App\Helpers\BienClientHelper;use App\Repository\BienClientRepository;use App\Repository\CercleRepository;use App\Repository\ExpertiseRepository;use App\Repository\KohUtilisateurRepository;use App\Repository\QuartierRepository;use App\Repository\RegionRepository;use App\Repository\StructureRepository;use App\Repository\TypeAcquisitionRepository;use App\Repository\TypeBienRepository;use App\Repository\TypeCompteRepository;use App\Repository\TypeDocumentProprieteRepository;use App\Repository\TypeUsageBienRepository;use Exception;use Sensio\Bundle\FrameworkExtraBundle\Configuration\Security;use Symfony\Bundle\FrameworkBundle\Controller\AbstractController;use Symfony\Component\HttpFoundation\JsonResponse;use Symfony\Component\HttpFoundation\RedirectResponse;use Symfony\Component\HttpFoundation\Request;use Symfony\Component\HttpFoundation\RequestStack;use Symfony\Component\HttpFoundation\Response;use Symfony\Component\Routing\Annotation\Route;class BienClientController extends AbstractController{    /**     * @var string     */    protected $baseUrl;    /**     * @var BienClientHelper     */    private $bienClientHelper;    /**     * @param RequestStack $requestStack     * @param BienClientHelper $bienClientHelper     */    public function __construct(RequestStack $requestStack, BienClientHelper $bienClientHelper)    {        $this->baseUrl = $requestStack->getCurrentRequest()->getSchemeAndHttpHost();        $this->bienClientHelper = $bienClientHelper;    }    /**     * LA LISTE DES BIENS POUR LA PAGE INDEX DE STRUCTURE     * @Route("/admin/index-biens", name="admin.indexBienClientStructure")     * @param TypeCompteRepository $typeCompteRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeBienRepository $typeBienRepository     * @param RegionRepository $regionRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @return Response     */    public function indexForStructure(TypeCompteRepository $typeCompteRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeBienRepository $typeBienRepository, RegionRepository $regionRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository): Response    {        return $this->render('bien_client/index_bien_structure.html.twig', ['typeComptes' => $typeCompteRepository->findAll(), 'typeDocuments' => $typeDocumentProprieteRepository->findAll(), 'typeAcquisitions' => $typeAcquisitionRepository->findAll(), 'typeUsageBiens' => $typeUsageBienRepository->findAll(), 'typeBiens' => $typeBienRepository->findAll(), 'regions' => $regionRepository->findAll(), 'cercles' => $cercleRepository->findAll(), 'quartiers' => $quartierRepository->findAll()]);    }    /**     * LA LISTE DES BIENS POUR LA PAGE INDEX DE PARTICULIER     * @Route("/koh_archivage/admin/biens-particuliers", name="admin.indexBienClientParticulier")     * @param BienClientRepository $clientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeBienRepository $typeBienRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param RegionRepository $regionRepository     * @param TypeCompteRepository $typeCompteRepository     * @return Response     */    public function indexForParticulier(BienClientRepository $clientRepository, KohUtilisateurRepository $kohUtilisateurRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository, TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeBienRepository $typeBienRepository, TypeUsageBienRepository $typeUsageBienRepository, RegionRepository $regionRepository, TypeCompteRepository $typeCompteRepository): Response    {        return $this->render('bien_client/index_bien_particulier.html.twig', ['typeComptes' => $typeCompteRepository->findAll(), 'typeDocuments' => $typeDocumentProprieteRepository->findAll(), 'typeAcquisitions' => $typeAcquisitionRepository->findAll(), 'typeUsageBiens' => $typeUsageBienRepository->findAll(), 'typeBiens' => $typeBienRepository->findAll(), 'regions' => $regionRepository->findAll(), 'cercles' => $cercleRepository->findAll(), 'quartiers' => $quartierRepository->findAll()]);    }    /**     * LA PAGE DETAIL DU BIEN POUR LA STRUCTURE     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and !user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/bien-clients/structure-detail-bien/{id}", name="admin.detailBienClientStructure")     * @param Expertise $expertise     * @return Response     */    public function showForStructure(Expertise $expertise): ?Response    {        $bienClient = $expertise->getBienClient();        if ($bienClient === null) {            $this->addFlash('danger', 'Le bien client est null');        }        $bienClient->setLastExpertise($expertise);        return $this->render('bien_client/bien_structure_detail.html.twig', ['bien' => $bienClient]);    }    /**     * LA PAGE DETAIL DU BIEN POUR LE PARTICULIER     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and !user.getIsKohUser() and user.getIsConfirmed()")     * @Route("/admin/bien-clients/particulier-detail-bien/{id}", name="admin.detailBienClientParticulier")     * @param Expertise $expertise     * @return Response     */    public function showForParticulier(Expertise $expertise): ?Response    {        $bienClient = $expertise->getBienClient();        if ($bienClient === null) {            $this->addFlash('danger', 'Le bien client est null');        }        $bienClient->setLastExpertise($expertise);        return $this->render('bien_client/bien_particulier_detail.html.twig', ['bien' => $bienClient]);    }    /**     * LA PAGE MAP POUR LA STRUCTURE     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and !user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/admin/bien-clients/bien-client-structure-sur-map", name="admin.bien_structure_sur_map")     * @param TypeDocumentProprieteRepository $typeDocumentProprieteRepository     * @param TypeAcquisitionRepository $typeAcquisitionRepository     * @param TypeUsageBienRepository $typeUsageBienRepository     * @param TypeBienRepository $typeBienRepository     * @param RegionRepository $regionRepository     * @param CercleRepository $cercleRepository     * @param QuartierRepository $quartierRepository     * @return Response     */    public function mapBiensForStructure(TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeBienRepository $typeBienRepository, RegionRepository $regionRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository): Response    {        return $this->render('bien_client/bien_client_sur_map.html.twig', ['id' => $this->getUser()->getId(), 'typeDocuments' => $typeDocumentProprieteRepository->findAll(), 'typeAcquisitions' => $typeAcquisitionRepository->findAll(), 'typeUsageBiens' => $typeUsageBienRepository->findAll(), 'typeBiens' => $typeBienRepository->findAll(), 'regions' => $regionRepository->findAll(), 'cercles' => $cercleRepository->findAll(), 'quartiers' => $quartierRepository->findAll()]);    }    /**     * LA PAGE MAP POUR LE PARTICULIER     * @Security("is_granted('ROLE_ADMIN') and user.getIsActived() and !user.getIsKohUser() and user.getIsConfirmed() and user.getIsAdmin()")     * @Route("/admin/bien-clients/bien-client-particulier-sur-map", name="admin.bien_particulier_sur_map")     * @return Response     */    public function mapBiensForParticulier(TypeDocumentProprieteRepository $typeDocumentProprieteRepository, TypeAcquisitionRepository $typeAcquisitionRepository, TypeUsageBienRepository $typeUsageBienRepository, TypeBienRepository $typeBienRepository, RegionRepository $regionRepository, CercleRepository $cercleRepository, QuartierRepository $quartierRepository): ?Response    {        return $this->render('bien_client/bien_particulier_sur_map.html.twig', ['id' => $this->getUser()->getId(), 'typeDocuments' => $typeDocumentProprieteRepository->findAll(), 'typeAcquisitions' => $typeAcquisitionRepository->findAll(), 'typeUsageBiens' => $typeUsageBienRepository->findAll(), 'typeBiens' => $typeBienRepository->findAll(), 'regions' => $regionRepository->findAll(), 'cercles' => $cercleRepository->findAll(), 'quartiers' => $quartierRepository->findAll()]);    }    /**     * DATA JSON DES BIENS POUR INDEX POUR LA STRUTURE     * @Route("/get-structure-all-biens", methods={"GET"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataForIndexStruture(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $biens = $this->bienClientHelper->getBienClientSorted($request, $bienClientRepository, $kohUtilisateurRepository, $this->getUser());        $expertises = [];        foreach ($biens as $bien) {            $last = $bien->getExpertises()->last();            if ($last !== false) {                $expertises[] = $bien->getExpertises()->last();            }        }        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl), 200);    }    /**     * DATA JSON DES BIENS POUR INDEX POUR LE PARTICULIER     * @Route("/get-particulier-all-biens", methods={"GET"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataForIndexParticulier(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $biens = $this->bienClientHelper->getBienClientParticulierSorted($request, $bienClientRepository, $kohUtilisateurRepository, $this->getUser());        $expertises = [];        foreach ($biens as $bien) {            $last = $bien->getExpertises()->last();            if ($last !== false) {                $expertises[] = $bien->getExpertises()->last();            }        }        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl), 200);    }    /**     * @Route("/koh_archivage/admin/biens-clients/get_biens")     * @param BienClientRepository $clientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @param StructureRepository $structureRepository     * @return JsonResponse     */    public function jsonDataForMapStructure(BienClientRepository $clientRepository, KohUtilisateurRepository $kohUtilisateurRepository, StructureRepository $structureRepository): JsonResponse    {        $user = $kohUtilisateurRepository->findOneBy(['username' => $this->getUser()->getUsername()]);        $structure = $structureRepository->findOneBy(['name' => $user->getStructure()->getName()]);        $id = 0;        foreach ($structure->getKohUtilisateurs() as $u) {            if ($u->getIsAdmin()) {                $id = $u->getId();            }        }        if ($id !== 0) {            $biens = $clientRepository->bien_client($id);            $this->bienClientHelper->getLastExpertise($biens);            return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl, true), 200);        }        return new JsonResponse(null, 200);    }    /**     * @Route("/koh_archivage/admin/biens-particuliers/get_biens")     * @param BienClientRepository $clientRepository     * @return JsonResponse     */    public function jsonDataForMapParticulier(BienClientRepository $clientRepository): JsonResponse    {        $biens = $clientRepository->bien_client($this->getUser()->getId());        $this->bienClientHelper->getLastExpertise($biens);        return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl, true), 200);    }    /**     * DATA JSON DES BIENS SELON LES CRITERES POUR INDEX POUR LA STRUCTURE     * @Route("/koh-archivage/get-biens-structure-by-critere", methods={"POST"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataByCritereForIndex(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $parameters = $request->request->all();        $adminUser = $kohUtilisateurRepository->findOneBy(['structure' => $this->getUser()->getStructure(), 'isAdmin' => true]);        $biens = [];        if ($parameters !== []) {            $biens = $bienClientRepository->getBienByCritereAndUser($parameters, $adminUser->getId());        }        $expertises = [];        foreach ($biens as $bien) {            $last = $bien->getExpertises()->last();            if ($last !== false) {                $expertises[] = $last;            }        }        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl));    }    /**     * DATA JSON DES BIENS SELON LES CRITERES POUR INDEX POUR LE PARTICULIER     * @Route("/koh-archivage/get-biens-particulier-by-critere", methods={"POST"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataByCritereForIndexParticulier(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $parameters = $request->request->all();        $biens = [];        if ($parameters !== []) {            $biens = $bienClientRepository->getBienByCritereAndUser($parameters, $this->getUser()->getId());        }        $expertises = [];        foreach ($biens as $bien) {            $last = $bien->getExpertises()->last();            if ($last !== false) {                $expertises[] = $last;            }        }        return new JsonResponse($this->bienClientHelper->serialiseExpertises($expertises, $this->baseUrl));    }    /**     * DATA JSON DES BIENS SELON DES CRITERES POUR MAP POUR LA STRUCTURE     * @Route("/koh-archivage/get-biens-by-critere-and-user", methods={"POST"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataByCritereForMapStructure(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $parameters = $request->request->all();        $structure = $kohUtilisateurRepository->findOneBy(['id' => $parameters['userId']])->getStructure();        $userAdmin = $kohUtilisateurRepository->findOneBy(['isAdmin' => true, 'structure' => $structure]);        $biens = [];        if ($parameters !== []) {            $biens = $bienClientRepository->getBienByCritereAndUser($parameters, $userAdmin->getId());            $this->bienClientHelper->getLastExpertise($biens);        }        return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl, true));    }    /**     * DATA JSON DES BIENS SELON DES CRITERES POUR MAP POUR LE PARTICULIER     * @Route("/koh-archivage/get-biens-particulier-by-critere-and-user", methods={"POST"})     * @param Request $request     * @param BienClientRepository $bienClientRepository     * @param KohUtilisateurRepository $kohUtilisateurRepository     * @return JsonResponse     */    public function jsonDataByCritereForMapParticulier(Request $request, BienClientRepository $bienClientRepository, KohUtilisateurRepository $kohUtilisateurRepository): JsonResponse    {        $parameters = $request->request->all();        $biens = [];        if ($parameters !== []) {            $biens = $bienClientRepository->getBienByCritereAndUser($parameters, $this->getUser()->getId());            $this->bienClientHelper->getLastExpertise($biens);        }        return new JsonResponse($this->bienClientHelper->serializeBiens($biens, $this->baseUrl, true));    }    /**     * @Route("/admin/bien-clients/edit/{id}/add-info", methods={"POST"}, name="admin.bienClient_addInfo")     * @param Request $request     * @param Expertise $expertise     * @return RedirectResponse     * @throws Exception     */    public function addInformationToBien(Request $request, Expertise $expertise): RedirectResponse    {        $em = $this->getDoctrine()->getManager();        $this->bienClientHelper->saveInformations($request, $expertise, $em, $this->getUser());        $this->addFlash('success', 'Les informations ont été enregistrées !');        return $this->redirectToRoute('admin.detailBienClientStructure', ['id' => $expertise->getId()]);    }    /**     * @Route("/admin/bien-clients/{id}/delete-memo", name="admin.bienClient_deleteMemo")     * @param Request $request     * @param MemoBien $memoBien     * @return RedirectResponse     */    public function deleteMemoExpertise(Request $request, MemoBien $memoBien): RedirectResponse    {        if ($this->isCsrfTokenValid('delete' . $memoBien->getId(), $request->request->get('_token'))) {            $em = $this->getDoctrine()->getManager();            $em->remove($memoBien);            $em->flush();            $this->addFlash('success', 'Le mémo a été supprimé !');        }        return $this->redirectToRoute('admin.detailBienClientStructure', ['id' => $memoBien->getExpertise()->getId()]);    }    /**     * @Route("/admin/bien-clients/{id}/delete-remarque", name="admin.bienClient_deleteRemarque")     * @param Request $request     * @param RemarqueBien $remarqueBien     * @return RedirectResponse     */    public function deleteRemarqueExpertise(Request $request, RemarqueBien $remarqueBien): RedirectResponse    {        if ($this->isCsrfTokenValid('delete' . $remarqueBien->getId(), $request->request->get('_token'))) {            $em = $this->getDoctrine()->getManager();            $em->remove($remarqueBien);            $em->flush();            $this->addFlash('success', 'La remarque a été supprimée !');        }        return $this->redirectToRoute('admin.detailBienClientStructure', ['id' => $remarqueBien->getExpertise()->getId()]);    }    /**     * @Route("/admin/bien-clients/{id}/delete-other-info", name="admin.bienClient_deleteOtherInfo")     * @param Request $request     * @param OtherInfoBien $infoBien     * @return RedirectResponse     */    public function deleteOtherInfoExpertise(Request $request, OtherInfoBien $infoBien): RedirectResponse    {        if ($this->isCsrfTokenValid('delete' . $infoBien->getId(), $request->request->get('_token'))) {            $em = $this->getDoctrine()->getManager();            $em->remove($infoBien);            $em->flush();            $this->addFlash('success', 'La remarque a été supprimée !');        }        return $this->redirectToRoute('admin.detailBienClientStructure', ['id' => $infoBien->getExpertise()->getId()]);    }}